$file_path = "docs/01B_DIAGRAM_AKTIVITAS_PUBLIK.md";
$content = file_get_contents($file_path);

$parts = preg_split('/\*\*Penjelasan:\*\*\s*\r?\n/', $content);

if (count($parts) != 21) {
    echo "Error: Found " . (count($parts) - 1) . " explanations instead of 20.\n";
    exit(1);
}

$new_content = $parts[0];

for ($i = 1; $i <= 20; $i++) {
    $desc = $descriptions[$i - 1];
    $old_desc_part = $parts[$i];
    
    // Find the end of the old paragraph indicated by '---'
    $split_next = preg_split('/(\r?\n){2,}---(\r?\n)/', $old_desc_part, 2);
    
    if (count($split_next) == 1) {
        $split_next = preg_split('/\r?\n---(\r?\n)/', $old_desc_part, 2);
    }
    
    $new_content .= "**Penjelasan:**\n" . $desc . "\n\n";
    
    if (count($split_next) > 1) {
        $new_content .= "---\n" . $split_next[1];
    }
}

file_put_contents($file_path, $new_content);
echo "Success: Refactored all 20 explanations in PHP to pure academic formal path.\n";
